sql:
SELECT COUNT(*) 
FROM coatings 
WHERE thickness > 15;

SELECT COUNT(check_id) AS quality_check_count
FROM quality_checks
WHERE coating_id = 1;

SELECT coating_id
FROM quality_checks
WHERE result = 'Fail';

SELECT COUNT(*)
FROM testing_results
WHERE test_parameter = 'Corrosion Resistance' AND test_result = 'Fail';

SELECT COUNT(*) AS available_racks
FROM racks
WHERE status = 'Available';

SELECT coating_name, type
FROM coatings
ORDER BY type;

SELECT status
FROM racks
WHERE status = 'In Use';

SELECT coating_name
FROM coatings
WHERE thickness = (SELECT MAX(thickness) FROM coatings);

SELECT COUNT(*) AS good_barrel_count
FROM barrels
WHERE location = 'Warehouse B' AND condition = 'Good';

SELECT coating_name, thickness
FROM coatings
ORDER BY thickness DESC;

SELECT COUNT(check_id) AS total_failed_checks
FROM quality_checks
WHERE result = 'Fail';

SELECT coating_name
FROM coatings
ORDER BY coating_name ASC;
